<template>
  <div class="todo-item">
    <!-- 不使用v-model，绑定checked，change时派发事件 -->
    <input
      type="checkbox"
      :checked="task.completed"
      @change="$emit('toggle-completed', index)"
    >
    <span :class="{ finished: task.completed }">{{ task.text }}</span>
    <button class="del-btn" @click="$emit('delete-task', index)">删除</button>
  </div>
</template>

<script>
export default {
  props: {
    task: Object,
    index: Number
  }
}
</script>
<style scoped>
.todo-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 16px;
  border-bottom: 1px solid #eee;
  transition: all 0.3s ease;
}
.todo-item:hover {
  background: #fafafa;
}
.finished {
  text-decoration: line-through;
  color: #999;
}
.del-btn {
  margin-left: auto;
  border: none;
  background: #e74c3c;
  color: white;
  padding: 6px 12px;
  border-radius: 4px;
  cursor: pointer;
  transition: background 0.2s;
}
.del-btn:hover {
  background: #c0392b;
}
</style>