<template>
  <div class="todo-footer">
    <div class="count">
      总计：{{ totalCount }} 条 | 未完成：{{ activeCount }} 条 | 已完成：{{ completedCount }} 条
    </div>
    <div class="filter-btns">
      <button
        v-for="item in filterOptions"
        :key="item.val"
        :class="{ active: filterStatus === item.val }"
        @click="$emit('change-filter', item.val)"
      >
        {{ item.label }}
      </button>
    </div>
    <button
      class="clear-btn"
      :disabled="completedCount === 0"
      @click="$emit('clear-completed')"
    >
      清除已完成任务
    </button>
  </div>
</template>

<script>
export default {
  props: {
    taskList: Array,
    filterStatus: String
  },
  data() {
    return {
      filterOptions: [
        { label: '全部', val: 'all' },
        { label: '未完成', val: 'active' },
        { label: '已完成', val: 'completed' }
      ]
    }
  },
  computed: {
    totalCount() {
      return this.taskList.length
    },
    completedCount() {
      return this.taskList.filter(t => t.completed).length
    },
    activeCount() {
      return this.taskList.filter(t => !t.completed).length
    }
  }
}
</script>

<style scoped>
.todo-footer {
  background: #f5f5f5;
  padding: 16px 20px;
  border-radius: 8px;
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  align-items: center;
  justify-content: space-between;
}
.count {
  color: #666;
  font-size: 14px;
}
.filter-btns {
  display: flex;
  gap: 8px;
}
.filter-btns button {
  border: 1px solid #ddd;
  background: #fff;
  padding: 6px 12px;
  border-radius: 4px;
  cursor: pointer;
}
.filter-btns button.active {
  background: #42b983;
  color: white;
  border-color: #42b983;
}
.clear-btn {
  border: none;
  background: #e67e22;
  color: white;
  padding: 6px 14px;
  border-radius: 4px;
  cursor: pointer;
}
.clear-btn:disabled {
  background: #bdc3c7;
  cursor: not-allowed;
}
</style>