<template>
  <div class="todo-header">
    <h1>任务管理系统</h1>
    <div class="input-wrap">
      <input
        v-model="inputText"
        placeholder="请输入新任务，回车/点击添加"
        @keyup.enter="add"
      >
      <button @click="add">添加任务</button>
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      inputText: ''
    }
  },
  methods: {
    add() {
      // 向父组件派发事件
      this.$emit('add-task', this.inputText)
      // 清空输入框
      this.inputText = ''
    }
  }
}
</script>

<style scoped>
.todo-header {
  background: #f5f5f5;
  padding: 20px;
  border-radius: 8px;
  margin-bottom: 20px;
}
h1 {
  text-align: center;
  color: #333;
  margin-top: 0;
}
.input-wrap {
  display: flex;
  gap: 10px;
}
input {
  flex: 1;
  padding: 10px 12px;
  border: 1px solid #ddd;
  border-radius: 4px;
  font-size: 16px;
}
button {
  padding: 10px 20px;
  border: none;
  background: #42b983;
  color: #fff;
  border-radius: 4px;
  cursor: pointer;
  transition: background 0.2s;
}
button:hover {
  background: #359469;
}
</style>