<template>
  <div class="todo-list">
    <!-- 空状态提示 -->
    <div v-if="taskList.length === 0" class="empty-tip">
      暂无任务，快去添加一个吧！
    </div>
    <!-- 循环渲染单任务 -->
    <TodoItem
      v-for="(item, idx) in taskList"
      :key="item.id"
      :task="item"
      :index="idx"
      @toggle-completed="$emit('toggle-completed', idx)"
      @delete-task="$emit('delete-task', idx)"
    />
  </div>
</template>

<script>
import TodoItem from './TodoItem.vue'
export default {
  components: { TodoItem },
  props: {
    taskList: Array
  }
}
</script>

<style scoped>
.todo-list {
  border: 1px solid #eee;
  border-radius: 8px;
  overflow: hidden;
  margin-bottom: 20px;
}
.empty-tip {
  padding: 40px;
  text-align: center;
  color: #aaa;
  font-size: 16px;
}
</style>