<template>
  <div class="todo-container">
    <!-- 头部添加任务组件 -->
    <TodoHeader @add-task="handleAddTask" />
    <!-- 任务列表区域 -->
    <TodoList
      :task-list="filteredTaskList"
      @toggle-completed="handleToggleCompleted"
      @delete-task="handleDeleteTask"
    />
    <!-- 底部统计+筛选+批量操作 -->
    <TodoFooter
      :task-list="taskList"
      :filter-status="filterStatus"
      @change-filter="handleChangeFilter"
      @clear-completed="handleClearCompleted"
    />
  </div>
</template>

<script>
// 引入所有子组件
import TodoHeader from './components/TodoHeader.vue'
import TodoList from './components/TodoList.vue'
import TodoFooter from './components/TodoFooter.vue'

// TodoList.vue


export default {
  components: { TodoHeader, TodoList, TodoFooter },
  data() {
    return {
      // 输入框临时文本（子组件内部维护，此处仅通信）
      newTaskText: '',
      // 全部任务列表
      taskList: [
        { id: 1789012345678, text: '完成Vue上机作业', completed: false },
        { id: 1789012399999, text: '复习组件通信', completed: true }
      ],
      // 筛选状态：all全部 / active未完成 / completed已完成
      filterStatus: 'all'
    }
  },
  created() {
    // 页面加载时读取本地存储
    const localData = localStorage.getItem('todoList')
    if (localData) {
      this.taskList = JSON.parse(localData)
    }
  },
  watch: {
    // 深度监听数组变化，自动持久化到localStorage
    taskList: {
      handler(newVal) {
        localStorage.setItem('todoList', JSON.stringify(newVal))
      },
      deep: true
    }
  },
 computed: {
  filteredTaskList() {
    if (this.filterStatus === 'all') {
      return this.taskList
    }
    if (this.filterStatus === 'active') {
      return this.taskList.filter(item => !item.completed)
    }
    if (this.filterStatus === 'completed') {
      return this.taskList.filter(item => item.completed)
    }
    // 兜底分支，任意异常状态默认返回全部任务，消除eslint报错
    return this.taskList
  }
},
  methods: {
    // 接收子组件新增任务
    handleAddTask(text) {
      const trimText = text.trim()
      if (!trimText) {
        alert('任务内容不能为空！')
        return
      }
      // 时间戳作为唯一ID
      const newTask = {
        id: Date.now(),
        text: trimText,
        completed: false
      }
      this.taskList.push(newTask)
    },
    // 切换任务完成状态
    handleToggleCompleted(index) {
      this.filteredTaskList[index].completed = !this.filteredTaskList[index].completed
    },
    // 删除任务
    handleDeleteTask(index) {
      if (confirm('确定要删除这条任务吗？')) {
        // 找到原数组下标
        const realItem = this.filteredTaskList[index]
        const realIndex = this.taskList.findIndex(t => t.id === realItem.id)
        this.taskList.splice(realIndex, 1)
      }
    },
    // 修改筛选条件
    handleChangeFilter(status) {
      this.filterStatus = status
    },
    // 清空已完成任务
    handleClearCompleted() {
      this.taskList = this.taskList.filter(item => !item.completed)
    }
  }
}
</script>

<style scoped>
.todo-container {
  max-width: 600px;
  margin: 50px auto;
  padding: 0 20px;
  font-family: "Microsoft Yahei", sans-serif;
}
</style>